import statistics

def benchmark_latency(
    prompt: str,
    runs: int = 20,
    max_tokens: int = 128,
) -> dict:
    ttfts = []
    e2es = []
    toks_per_sec = []

    for _ in range(runs):
        m = measure_latency(prompt, max_tokens)
        if m["ttft_s"] is not None:
            ttfts.append(m["ttft_s"])
        e2es.append(m["e2e_s"])
        toks_per_sec.append(m["tokens_per_sec"])

    def pct(data: list[float], p: int) -> float:
        data_sorted = sorted(data)
        idx = int(len(data_sorted) * p / 100)
        return round(data_sorted[min(idx, len(data_sorted) - 1)], 3)

    return {
        "ttft": {"p50": pct(ttfts, 50), "p90": pct(ttfts, 90), "p99": pct(ttfts, 99)},
        "e2e":  {"p50": pct(e2es, 50),  "p90": pct(e2es, 90),  "p99": pct(e2es, 99)},
        "tokens_per_sec": {"mean": round(statistics.mean(toks_per_sec), 1)},
    }

result = benchmark_latency("Summarise this document: " + "word " * 500, runs=20)
print(result)
